"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[5983],{8827(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>c,frontMatter:()=>a,metadata:()=>s,toc:()=>l});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-21","title":"Discourses \u2014 Book 2, Chapter 21","description":"Book 2 \u2014 Chapter 21","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-21.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-21","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-21","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":22,"frontMatter":{"sidebar_position":22,"title":"Discourses \u2014 Book 2, Chapter 21","sidebar_label":"Book 2, Ch. 21"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 20","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-20"},"next":{"title":"Book 2, Ch. 22","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-22"}}');var n=t(4848),i=t(8453);const a={sidebar_position:22,title:"Discourses \u2014 Book 2, Chapter 21",sidebar_label:"Book 2, Ch. 21"},r="Discourses",h={},l=[{value:"Book 2 \u2014 Chapter 21",id:"book-2--chapter-21",level:2},{value:"Concerning Inconsistency Of Mind",id:"concerning-inconsistency-of-mind",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function u(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,i.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(o.header,{children:(0,n.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(o.h2,{id:"book-2--chapter-21",children:"Book 2 \u2014 Chapter 21"}),(0,n.jsx)(o.h3,{id:"concerning-inconsistency-of-mind",children:"Concerning Inconsistency Of Mind"})]}),"\n",(0,n.jsx)(o.p,{children:(0,n.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(t,{open:!0,children:[(0,n.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,n.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,n.jsx)(o.p,{children:"People readily admit to cowardice or pity \u2014 qualities they can frame as soft-heartedness \u2014 but not to injustice, incontinence, or envy. The reason is partly that they see an involuntary element in the former and not the latter, and partly that different vices carry different social stigma. The deeper reason is confusion about what is actually good and evil."}),(0,n.jsx)(o.p,{children:"The chapter then turns inward: are you one of these people? Epictetus lists the symptoms \u2014 coming to school distracted by home politics, thinking about your reputation back in Nicopolis, sitting in class mentally elsewhere while your housemates are watching your progress from afar. If you come to school to chatter about principles, you'll leave with a lighter tongue \u2014 that's exactly what you came for. The question is whether what you came for is what you actually need. Like a patient with a stomach ulcer being offered vinegar: theoretically useful, currently harmful. First heal the underlying condition, then apply the more powerful tools."})]}),"\n",(0,n.jsxs)(t,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(o.h2,{id:"text",children:"Text"}),(0,n.jsx)(o.p,{children:"THERE are some admissions which men readily make, others they do not. Now no one will admit that he is thoughtless or foolish: on the contrary, you will hear every one say, 'Would that I had luck as I have wits!' But men readily admit that they are cowards and say, 'I am a bit of a coward, I admit, but for the rest you will find me no fool'. A man will not readily own to incontinence, to injustice not at all, never"}),(0,n.jsx)(o.p,{children:"to envy or fussiness, while most men will own to being pitiful. You ask what is the reason? The most vital reason is a confusion and want of consistency in men's views of what is good and evil, but, apart from this, different persons are affected by different motives; speaking generally, people are not ready to own to qualities which to their mind appear base. Cowardice and a sense of pity they imagine show good nature, silliness a slavish mind, and social faults they are least ready to admit. In most of the errors which they are inclined to confess to, it is because they think there is an involuntary element, as in the cowardly and the pitiful. So if any one does own to incontinence, he brings in passion, to give him the excuse of involuntary action. Injustice is in no circumstances conceived as involuntary. There is an involuntary element, they think, in jealousy, and for this reason this too is a fault which men confess."}),(0,n.jsx)(o.p,{children:"Moving, then, as we do among men of this character, so bewildered, so ignorant of what they are saying, or of what evil is theirs, or whether they have any, or what is the reason of it, or how they are to be relieved, we ought ourselves, I think, to be constantly on our guard, asking ourselves, 'Am I too perhaps one of them? What impression have I of myself? How do I bear myself? Do I too bear myself as a man of prudence and self-control? Do I too sometimes say that I am educated to meet every emergency? Am I conscious, as the man who knows nothing should be, that I know nothing? Do I come to my teacher as to the oracles, prepared to obey, or do I too come to school like a driveller, to learn nothing but history and to understand the books which I did not understand before, and if it so chance, to expound them to others?'"}),(0,n.jsx)(o.p,{children:"Man, you have had a boxing match with your slave at home, and turned your house upside down and disturbed your neighbours, and now do you come to me with a solemn air like a wise man and sit and criticize the way I interpret language, and how I rattle out anything that comes into my head? Do you come in a spirit of envy, depressed because nothing is brought you from home, and while the discussion is going on, sit thinking of nothing yourself but how you stand with your father or your brother? 'What are men at home saying about me? They are thinking now that I am making progress and say, \"He will come back knowing everything\". I did indeed wish to return one day if I could, having learnt everything, but it needs hard work, and no one sends me anything and the baths are shockingly bad in Nicopolis, and I am badly off in my lodgings and in the lecture-room.'"}),(0,n.jsx)(o.p,{children:"Then they say, 'No one gets any good from the lecture-room!'"}),(0,n.jsx)(o.p,{children:"Why, who comes to the lecture-room? Who comes to be cured? Who comes to have his judgements purified? Who comes that he may grow"}),(0,n.jsx)(o.p,{children:"conscious of his needs? Why are you surprised, then, that you carry away from school the very qualities you bring there, for you do not come to put away your opinions or to correct them, or to get others in exchange? No, far from it! What you must look to is whether you get what you come for. You wish to chatter about principles. Well, do you not come away with lighter tongues than before? Does not school afford you material for displaying your precious principles? Do you not analyse variable syllogisms? Do you not pursue the assumptions of 'The Liar'  and hypothetical propositions? Why then do you go on being vexed at getting what you come for?"}),(0,n.jsx)(o.p,{children:"'Yes, but if my child or my brother die, or if I must be racked and die myself, what good will such things do me?'"}),(0,n.jsx)(o.p,{children:"What! is this what you came for? Is this what you sit by me for? Did you ever light your lamp or sit up late for this? Or, when you have gone out for a walk, have you ever put a conception before your mind instead of a syllogism and pursued this with your companion? When have you ever done so? Then you say, 'Principles are useless.' To whom? To those who use them wrongly. For collyrium is not useless to those who anoint themselves at the right time and in the right way, plasters are not useless, leaping-weights are not useless, but only useless to some, and again useful to others."}),(0,n.jsx)(o.p,{children:"If you ask me now, 'Are syllogisms useful?' I shall say they are useful, and if you wish I will prove it."}),(0,n.jsx)(o.p,{children:"'What good have they done me then?'"}),(0,n.jsx)(o.p,{children:"Man, did you ask whether they were useful in general, or useful to you? Suppose a man suffering from dysentery asked me, 'Is vinegar useful?' I shall say it is. 'Is it useful to me?' I shall say: 'No; seek first to get your flux stayed, and your ulcerations healed.' It is the same with you. You must first attend to your ulcers, and stay your flux, and arrive at peace in your mind and bring it to school undistracted, and then you will discover how wonderful the power of reason is."})]})]})}function c(e={}){const{wrapper:o}={...(0,i.R)(),...e.components};return o?(0,n.jsx)(o,{...e,children:(0,n.jsx)(u,{...e})}):u(e)}},8453(e,o,t){t.d(o,{R:()=>a,x:()=>r});var s=t(6540);const n={},i=s.createContext(n);function a(e){const o=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:a(e.components),s.createElement(i.Provider,{value:o},e.children)}}}]);